const health = $input.first().json || {};
const account = health.account || {};
const guard = health.guard || {};
const config = health.mt5_connection_config || {};
const guardBlockers = Array.isArray(guard.blockers) ? guard.blockers : [];
const accountBlockers = Array.isArray(guard.live_account_blockers) ? guard.live_account_blockers : [];
const tradeMode = account.trade_mode_label || 'unknown';
const demoModeOk = ['demo', 'contest'].includes(tradeMode);
const ready = Boolean(
  health.ok === true &&
  health.live_enabled === true &&
  account.connected === true &&
  demoModeOk &&
  guard.ok === true &&
  guardBlockers.length === 0 &&
  accountBlockers.length === 0
);

return [{
  json: {
    ok: ready,
    bridge_ready: ready,
    status: ready ? 'demo_live_ready' : 'blocked',
    live_enabled: health.live_enabled === true,
    mt5_connected: account.connected === true,
    trade_mode: tradeMode,
    demo_mode_ok: demoModeOk,
    guard_ok: guard.ok === true,
    real_allowed: config.allow_real_account === true,
    require_demo_account: config.require_demo_account !== false,
    blockers: [...guardBlockers, ...accountBlockers, ...(health.ok === true ? [] : ['MT5 bridge health endpoint did not return ok=true.'])],
    checked_at: new Date().toISOString()
  }
}];

const calendar = $input.first().json || {};
const highEvents = Array.isArray(calendar.events)
  ? calendar.events.filter((event) => String(event.impact || '').toLowerCase() === 'high')
  : [];
const riskLevel = String(calendar.riskLevel || 'unknown').toLowerCase();
const blocked = calendar.ok !== true || riskLevel === 'high' || highEvents.length > 0;

return [{
  json: {
    macro_clear: !blocked,
    macro_risk_level: riskLevel,
    calendar_source: calendar.source || 'unknown',
    high_impact_count: highEvents.length,
    high_impact_events: highEvents.slice(0, 5).map((event) => ({
      time: event.time,
      currency: event.currency,
      event: event.event,
      action: event.action
    })),
    checked_at: new Date().toISOString()
  }
}];

const history = $input.first().json || {};
const strategy = $('Load scanner strategies').item.json;
const prices = history.prices || [];
const volumes = history.total_volumes || [];
const conditions = strategy.conditions || {};
const minLookback = Math.max(conditions.price_above_ema || 0, 50);

if (prices.length < minLookback + 1) {
  return [{ json: { ...strategy, ok: false, reason: 'Not enough hourly candles', signal: false } }];
}

const closes = prices.map((row) => Number(row[1])).filter((value) => Number.isFinite(value));
const volumeValues = volumes.map((row) => Number(row[1])).filter((value) => Number.isFinite(value));
const currentPrice = closes.at(-1);
const previousPrice = closes.at(-2);

function calculateEMA(values, period) {
  if (!period || values.length < period) return null;
  let ema = values.slice(0, period).reduce((sum, value) => sum + value, 0) / period;
  const multiplier = 2 / (period + 1);
  for (let index = period; index < values.length; index += 1) {
    ema = (values[index] - ema) * multiplier + ema;
  }
  return ema;
}

function calculateRSI(values, period = 14) {
  if (values.length < period + 1) return null;
  let gains = 0;
  let losses = 0;
  for (let index = 1; index <= period; index += 1) {
    const diff = values[index] - values[index - 1];
    if (diff >= 0) gains += diff;
    else losses -= diff;
  }
  let avgGain = gains / period;
  let avgLoss = losses / period;
  for (let index = period + 1; index < values.length; index += 1) {
    const diff = values[index] - values[index - 1];
    if (diff >= 0) {
      avgGain = (avgGain * (period - 1) + diff) / period;
      avgLoss = (avgLoss * (period - 1)) / period;
    } else {
      avgGain = (avgGain * (period - 1)) / period;
      avgLoss = (avgLoss * (period - 1) - diff) / period;
    }
  }
  if (avgLoss === 0) return 100;
  const rs = avgGain / avgLoss;
  return 100 - (100 / (1 + rs));
}

function calculateMACD(values, fast = 12, slow = 26) {
  if (values.length < slow * 2) return null;
  const macdLine = calculateEMA(values, fast) - calculateEMA(values, slow);
  const previousValues = values.slice(0, -1);
  const previousMacd = calculateEMA(previousValues, fast) - calculateEMA(previousValues, slow);
  return {
    value: macdLine,
    previous: previousMacd,
    bullish: macdLine > 0 && macdLine > previousMacd,
    bearish: macdLine < 0 && macdLine < previousMacd
  };
}

function calculateVolumeSpike(values, lookback = 20) {
  if (values.length < lookback + 1) return 1;
  const current = values.at(-1);
  const recent = values.slice(-lookback - 1, -1);
  const average = recent.reduce((sum, value) => sum + value, 0) / recent.length;
  return average > 0 ? current / average : 1;
}

const emaPeriod = conditions.price_above_ema || conditions.price_below_ema || null;
const ema = emaPeriod ? calculateEMA(closes, emaPeriod) : null;
const rsi = (conditions.rsi_below || conditions.rsi_above) ? calculateRSI(closes, 14) : null;
const macd = (conditions.macd_bullish || conditions.macd_bearish) ? calculateMACD(closes) : null;
const volumeSpike = conditions.volume_spike ? calculateVolumeSpike(volumeValues, 20) : 1;
const atrProxy = Math.max(currentPrice * 0.01, Math.abs(currentPrice - previousPrice) * 2);
const reasons = [];
let signal = true;

if (conditions.price_above_ema) {
  const passed = ema !== null && currentPrice > ema;
  if (!passed) {
    signal = false;
    reasons.push('Price is not above EMA' + conditions.price_above_ema);
  }
}

if (conditions.price_below_ema) {
  const passed = ema !== null && currentPrice < ema;
  if (!passed) {
    signal = false;
    reasons.push('Price is not below EMA' + conditions.price_below_ema);
  }
}

if (conditions.rsi_below) {
  const passed = rsi !== null && rsi < conditions.rsi_below;
  if (!passed) {
    signal = false;
    reasons.push('RSI is not below ' + conditions.rsi_below);
  }
}

if (conditions.rsi_above) {
  const passed = rsi !== null && rsi > conditions.rsi_above;
  if (!passed) {
    signal = false;
    reasons.push('RSI is not above ' + conditions.rsi_above);
  }
}

if (conditions.macd_bullish && !(macd && macd.bullish)) {
  signal = false;
  reasons.push('MACD is not bullish');
}

if (conditions.macd_bearish && !(macd && macd.bearish)) {
  signal = false;
  reasons.push('MACD is not bearish');
}

if (conditions.volume_spike && volumeSpike < conditions.volume_spike) {
  signal = false;
  reasons.push('Volume spike is below ' + conditions.volume_spike + 'x');
}

const stopLoss = strategy.direction === 'LONG'
  ? Number((currentPrice * Number(strategy.slPercent || 0.98)).toFixed(2))
  : Number((currentPrice * (2 - Number(strategy.slPercent || 0.98))).toFixed(2));
const takeProfit = strategy.direction === 'LONG'
  ? Number((currentPrice * Number(strategy.tpPercent || 1.02)).toFixed(2))
  : Number((currentPrice * (2 - Number(strategy.tpPercent || 1.02))).toFixed(2));
const rr = Number((Math.abs(takeProfit - currentPrice) / Math.max(Math.abs(currentPrice - stopLoss), 1)).toFixed(2));
const indicatorSummary = {
  emaPeriod,
  ema: ema === null ? null : Number(ema.toFixed(2)),
  rsi14: rsi === null ? null : Number(rsi.toFixed(2)),
  macdValue: macd ? Number(macd.value.toFixed(4)) : null,
  macdBullish: macd ? macd.bullish : false,
  volumeSpike: Number(volumeSpike.toFixed(2))
};

return [{
  json: {
    ...strategy,
    ok: true,
    current_price: Number(currentPrice.toFixed(2)),
    indicators: indicatorSummary,
    ema: indicatorSummary.ema,
    rsi: indicatorSummary.rsi14,
    macd_bullish: indicatorSummary.macdBullish,
    volume_spike: indicatorSummary.volumeSpike,
    signal,
    entry: Number(currentPrice.toFixed(2)),
    stopLoss,
    takeProfit,
    rewardRisk: rr,
    rejectionReasons: reasons,
    timestamp: new Date().toISOString(),
    note: signal ? 'Candidate only. Zeus risk gate and manual approval are still required.' : reasons.join('; ')
  }
}];
